#!/usr/bin/env python3"""NICTO Super v3.0 ΓÇö Unified OrchestratorIntegrates all v3 subsystems into a single, powerful CLI:  - build: Generate 1M+ training data across 100+ domains  - train: Multi-stage SFT/DPO/GRPO training on frontier models  - benchmark: Compare against GPT-5.5, Claude, Gemini, DeepSeek V4  - improve: Continuous self-improvement loop  - status: Show current competitive standing  - pipeline: Run the full pipeline end-to-end  Usage:  python nicto_super_v3.py --help  python nicto_super_v3.py build --info  python nicto_super_v3.py benchmark  python nicto_super_v3.py improve --cycle 3"""import jsonimport osimport sysimport timefrom pathlib import PathHERE = Path(__file__).parentVERSION = "3.0.0"CODENAME = "SUPERTRAIN"def banner():    print()    print("=" * 70)    print("  * NICTO SUPER v3.0 - Autonomous Superintelligence Training *")    print("  Target: Surpass GPT-5.5, Claude Sonnet 5, Gemini 3.1 Pro, DeepSeek V4")    print("=" * 70)    print()def cmd_build(args):    """Build training data."""    from build_super_data_v3 import generate_dataset    banner()    print("  PHASE: BUILD TRAINING DATA")    print()        generate_dataset(        single_turn_per_domain=args.single_turn,        cot_count=args.cot,        programming_count=args.programming,        multi_turn_count=args.multi_turn,        adversarial_count=args.adversarial,        cross_domain_count=args.cross_domain,    )def cmd_train(args):    """Train NICTO."""    from train_super_v3 import main as train_main    # Import and run with namespace directly instead of sys.argv manipulation    import argparse as _argparse    train_parser = _argparse.ArgumentParser()    train_parser.add_argument("--mode", default=args.mode or "info")    train_parser.add_argument("--model", default=args.model or "qwen-32b")    train_parser.add_argument("--epochs", type=int, default=args.epochs or 3)    train_parser.add_argument("--data", default=None)    train_parser.add_argument("--output", default=None)    train_parser.add_argument("--batch-size", type=int, default=2)    train_parser.add_argument("--lr", type=float, default=2e-4)    train_parser.add_argument("--export-type", default="all")    train_args = train_parser.parse_args([])    # Monkey-patch sys.argv to make train_super_v3's argparse work    import sys as _sys    _sys.argv = ["train_super_v3.py", "--mode", train_args.mode, "--model", train_args.model,                 "--epochs", str(train_args.epochs)]    train_main()def cmd_benchmark(args):    """Run competitive benchmark."""    from benchmark_v3 import CompetitiveBenchmark    banner()    print("  PHASE: COMPETITIVE BENCHMARK")    print()        bench = CompetitiveBenchmark()        if args.record:        for name, score in args.record:            bench.record_nicto_score(name, float(score))        bench.generate_report()    bench.save_reports()        print()    print(bench.generate_leaderboard_text())def cmd_improve(args):    """Run continuous improvement."""    from continuous_improvement_v3 import ContinuousImprovementScheduler    banner()    print("  PHASE: CONTINUOUS IMPROVEMENT")    print()        scheduler = ContinuousImprovementScheduler()        if args.daemon:        import time as _time        print(f"  Running as daemon (interval: {args.interval}s)")        try:            while True:                scheduler.run_cycle(                    max_weaknesses=args.weaknesses,                    samples_per_weakness=args.samples,                )                print(f"\n  Next cycle in {args.interval}s...")                _time.sleep(args.interval)        except KeyboardInterrupt:            print("\n  Daemon stopped.")    else:        for i in range(args.cycle):            scheduler.run_cycle(                max_weaknesses=args.weaknesses,                samples_per_weakness=args.samples,            )def cmd_status(args):    """Show competitive status."""    from benchmark_v3 import CompetitiveBenchmark    from continuous_improvement_v3 import ContinuousImprovementScheduler    banner()    print("  STATUS: COMPETITIVE STANDING")    print()        # Benchmark status    bench = CompetitiveBenchmark()    bench.generate_report()    print(bench.generate_leaderboard_text())        # Improvement status    scheduler = ContinuousImprovementScheduler()    status = scheduler.get_status()    print()    print(f"  IMPROVEMENT STATUS")    print(f"  {'='*40}")    print(f"  Cycles completed: {status['cycle_count']}")    print(f"  Total examples generated: {status['total_examples_generated']:,}")    print(f"  Unique domains improved: {status['domains_improved']}")    print(f"  Replay buffer size: {status['replay_buffer_size']:,}")def cmd_pipeline(args):    """Run full pipeline end-to-end."""    banner()    print("  [1/4] FULL PIPELINE: Build -> Train -> Benchmark -> Improve")    print()        # Phase 1: Build data    print("[1/4] Building training data...")    from build_super_data_v3 import generate_dataset    t0 = time.time()    generate_dataset(        single_turn_per_domain=args.single_turn,        cot_count=min(args.cot, 1000),        programming_count=min(args.programming, 1000),        multi_turn_count=min(args.multi_turn, 500),        adversarial_count=min(args.adversarial, 500),        cross_domain_count=min(args.cross_domain, 200),    )    print(f"  Data build: {time.time()-t0:.1f}s")        # Phase 2: Export training scripts    print(f"\n[2/4] Exporting training scripts...")    from train_super_v3 import main as train_main    import sys as _sys    _sys.argv = ["train_super_v3.py", "--mode", "export", "--export-type", "all",                 "--model", args.model or "qwen-32b"]    train_main()        # Phase 3: Benchmark    print(f"\n[3/4] Running benchmarks...")    from benchmark_v3 import CompetitiveBenchmark    bench = CompetitiveBenchmark()    bench.generate_report()    bench.save_reports()        # Phase 4: Continuous improvement    print(f"\n[4/4] Starting improvement cycle...")    from continuous_improvement_v3 import ContinuousImprovementScheduler    scheduler = ContinuousImprovementScheduler()    scheduler.run_cycle(        max_weaknesses=args.weaknesses,        samples_per_weakness=min(args.samples, 500),    )        print()    print("=" * 70)    print("  FULL PIPELINE COMPLETE")    print("  NICTO is now smarter. Run again to continue improving.")    print("=" * 70)def main():    import argparse        parser = argparse.ArgumentParser(        description=f"NICTO Super v{VERSION} ΓÇö {CODENAME}",        formatter_class=argparse.RawTextHelpFormatter,    )    sub = parser.add_subparsers(dest="command", help="Command")        # build    p_build = sub.add_parser("build", help="Generate training data")    p_build.add_argument("--single-turn", type=int, default=15000, help="Examples per domain")    p_build.add_argument("--cot", type=int, default=5000, help="Chain-of-thought examples")    p_build.add_argument("--programming", type=int, default=5000, help="Programming examples")    p_build.add_argument("--multi-turn", type=int, default=2000, help="Multi-turn conversations")    p_build.add_argument("--adversarial", type=int, default=2000, help="Adversarial examples")    p_build.add_argument("--cross-domain", type=int, default=1000, help="Cross-domain examples")    p_build.add_argument("--info", action="store_true", help="Show config info")        # train    p_train = sub.add_parser("train", help="Train NICTO")    p_train.add_argument("--mode", default="info",                        choices=["info", "sft", "dpo", "grpo", "curriculum", "pipeline", "continuous", "export"])    p_train.add_argument("--model", default="qwen-32b",                        help="Model: deepseek-v4, llama-405b, qwen-72b, qwen-32b, mistral-large, gemma-27b")    p_train.add_argument("--epochs", type=int, default=3)    p_train.add_argument("--data", default=None)        # benchmark    p_bench = sub.add_parser("benchmark", help="Run competitive benchmark")    p_bench.add_argument("--record", type=str, nargs=2, action="append",                        help="Record NICTO score: --record benchmark_name score")        # improve    p_improve = sub.add_parser("improve", help="Run continuous improvement")    p_improve.add_argument("--cycle", type=int, default=1, help="Number of cycles")    p_improve.add_argument("--weaknesses", type=int, default=3, help="Max weaknesses per cycle")    p_improve.add_argument("--samples", type=int, default=1000, help="Samples per weakness")    p_improve.add_argument("--daemon", action="store_true", help="Run as daemon")    p_improve.add_argument("--interval", type=int, default=3600, help="Interval (seconds)")        # status    sub.add_parser("status", help="Show competitive standing")        # pipeline    p_pipe = sub.add_parser("pipeline", help="Run full pipeline")    p_pipe.add_argument("--model", default="qwen-32b")    p_pipe.add_argument("--single-turn", type=int, default=5000)    p_pipe.add_argument("--cot", type=int, default=1000)    p_pipe.add_argument("--programming", type=int, default=1000)    p_pipe.add_argument("--multi-turn", type=int, default=500)    p_pipe.add_argument("--adversarial", type=int, default=500)    p_pipe.add_argument("--cross-domain", type=int, default=200)    p_pipe.add_argument("--weaknesses", type=int, default=3)    p_pipe.add_argument("--samples", type=int, default=500)        args = parser.parse_args()        if not args.command:        parser.print_help()        banner()        print("\n  Commands:")        print("    build       Generate 1M+ training data across 100+ domains")        print("    train       Multi-stage SFT/DPO/GRPO training on frontier models")        print("    benchmark   Compare against GPT-5.5, Claude, Gemini, DeepSeek V4")        print("    improve     Continuous self-improvement loop")        print("    status      Show current competitive standing and improvement status")        print("    pipeline    Run the full pipeline end-to-end")        print()        return        commands = {        "build": cmd_build,        "train": cmd_train,        "benchmark": cmd_benchmark,        "improve": cmd_improve,        "status": cmd_status,        "pipeline": cmd_pipeline,    }        cmd = commands.get(args.command)    if cmd:        cmd(args)    else:        parser.print_help()if __name__ == "__main__":    main()